import React from "react";
import {Routes,Route} from 'react-router-dom';
import SignUp from "./components/SignUp";
import Login from "./components/Login";

function App(){
  return(
    <>
     <Routes>
        <Route path="/" element ={<SignUp/>}></Route>
        <Route path="/" element ={<Login/>}></Route>
    </Routes>
    </>
  )
}

export default App;
